                  Object objType = field.getValue();    
                  if ("contact".equalsIgnoreCase(objType)) {
                  if (form.getSection("Dial-in") != null) {
                  form.remove(form.getSection("Dial-in"));
                  }
                  if (form.getSection("User Details") != null) {
                  form.remove(form.getSection("User Details"));
                  }
                  if (form.getSection("Skype for Business") != null) {
                  form.remove(form.getSection("Skype for Business"));
                  } 

                  if (form.getSection("Exchange") != null && form.getSection("Exchange").getFields() != null ) {
                  for (Object field : form.getSection("Exchange").getFields()) {
                  String name = field.getName();
                  if (name != null && name.indexOf(":") > 0 ) {
                  String[] nameKeys = name.split(":");
                  if (nameKeys.length > 1 &&
                  "homeMDB".equalsIgnoreCase(nameKeys[2])){
                  field.setHidden(true);
                  }
                  }
                  }
                  }  

                  } else {
                  if (form.getSection("User Details") != null && form.getSection("User Details").getFields() != null ) {
                  for (Object field : form.getSection("User Details").getFields()) {
                  String name = field.getName();
                  if (name != null && name.indexOf(":") > 0 ) {
                  String[] nameKeys = name.split(":");
                  if (nameKeys.length > 1 &&
                  ("sAMAccountName".equalsIgnoreCase(nameKeys[2]) 
                  || "password".equalsIgnoreCase(nameKeys[2]))){
                  field.setRequired(true);
                  }
                  }
                  }
                  }

                  }

                  return false;

          import sailpoint.object.Identity;
          import sailpoint.object.Application;
          import sailpoint.object.Custom;
          import sailpoint.object.Link;
          import sailpoint.tools.Util;
          import sailpoint.api.IdentityService;

          Custom custDN = context.getObjectByName(Custom.class,"Ascension-Custom-AD-DomainMapping");
          HashMap domainMap = new HashMap();
          String createDN = null;
          String dName= null;
          String sAMName = "";
          String subType = "";
          IdentityService idSvc = new IdentityService(context);

          if(null != identity){
          Application amitaApp = context.getObjectByName(Application.class, "AD-AMITA");
          List adlinks = idSvc.getLinks(identity,amitaApp);
          subType = identity.getAttribute("userSubType");

          if(null != amitaApp && adlinks != null && adlinks.size() == 1){
          for(Link adlink : adlinks){
          if(adlink != null && Util.isNotNullOrEmpty(adlink.getAttribute("cn"))){
          sAMName = (adlink.getAttribute("cn")).toString().replaceAll(",","\\\\,");
          }
          }
          }

          if(custDN != null && null != custDN.get("DomainOUMapping")){
          domainMap = custDN.get("DomainOUMapping");
          if(null != domainMap && !domainMap.isEmpty() && null != domainMap.get("PRESENCEHEALTH")){  
          activeOUMap = domainMap.get("PRESENCEHEALTH").get("activeOU");
          if(null != activeOUMap && !activeOUMap.isEmpty()){
          if( Util.isNotNullOrEmpty(subType) && Util.isNotNullOrEmpty(activeOUMap.get(subType))){
          createDN = activeOUMap.get(subType);
          }
          else{
          createDN = activeOUMap.get("DEFAULT");
          }
          }
          }
          dName = "CN="+sAMName+","+createDN;
          }
          if(null!= custDN){
          //context.decache(custDN);
          }
          }
          return dName;

          import sailpoint.object.Identity;
          import sailpoint.object.Application;
          import sailpoint.tools.Util;
          import sailpoint.api.IdentityService;
          import sailpoint.object.Link;

          String sAMName = "";
          IdentityService idSvc = new IdentityService(context);

          if(null != identity){

          Application amitaApp = context.getObjectByName(Application.class, "AD-AMITA");
          List adlinks = idSvc.getLinks(identity,amitaApp);

          if(null != amitaApp && adlinks != null && adlinks.size() == 1){
          for(Link adlink : adlinks){
          sAMName = adlink.getAttribute("sAMAccountName");
          }
          }
          }   
          return sAMName;

          import sailpoint.object.Identity;
          import sailpoint.object.Link;
          import sailpoint.tools.Util;
          import sailpoint.object.Application;
          import sailpoint.api.IdentityService;

          String managerDN = null; 
          String appName = null;
          String accountName = null;
          List<Link> appLinks = null;

          if(identity  != null){

          Identity managerObj=identity.getManager();
          if(null != managerObj){
          IdentityService idService = new IdentityService(context);        
          Application app = context.getObjectByName(Application.class,"AD-PRESENCEHEALTH");		
          
          if(null != app && !Util.isEmpty((appLinks = idService.getLinks( identity, app)))){
          for(Link applink : appLinks){
          if(!applink.isDisabled()){
          managerDN=applink.getNativeIdentity();
          break;
          }           
          }
          }                       
          }
          }

          return managerDN;

String displayNameValue = "";
          if(null != identity){
          displayNameValue = identity.getLastname()+", "+identity.getFirstname();
          }  
          return displayNameValue;

          import sailpoint.object.ProvisioningPlan.AccountRequest; 
          import sailpoint.object.ProvisioningPlan.AttributeRequest;
          import sailpoint.tools.Util;

          String attValue = "";
          String sAMName = "";

          if(accountRequest != null && null != accountRequest.getAttributeRequest("sAMAccountName") && Util.isNotNullOrEmpty(accountRequest.getAttributeRequest("sAMAccountName").getValue())){
          sAMName = accountRequest.getAttributeRequest("sAMAccountName").getValue();   
          }

          if(null != identity){
          String middleVal = "";
          if(null != identity.getAttribute("middleName")){
          middleVal = identity.getAttribute("middleName");
          }
          attValue = identity.getLastname()+", "+identity.getFirstname()+" "+middleVal+", "+sAMName;
          }  
          return attValue;

          String attValue = null;

          if(null != identity){
          attValue = identity.getAttribute("employeeId");
          }  
          return attValue;

          String attValue = "";

          if(null != identity){
          attValue = identity.getAttribute("employeeId");
          }  
          return attValue;

          import sailpoint.object.Identity;
          import sailpoint.tools.Util;

          String vendorValue = null;

          if(null != identity && Util.isNotNullOrEmpty(identity.getAttribute("vendorName"))){         
          vendorValue = identity.getAttribute("vendorName");
          }

          return vendorValue;

          import sailpoint.object.ProvisioningPlan.AccountRequest; 
          import sailpoint.object.ProvisioningPlan.AttributeRequest;
          import sailpoint.tools.Util;

          String attValue = "";

          if(accountRequest != null && null != accountRequest.getAttributeRequest("sAMAccountName") && Util.isNotNullOrEmpty(accountRequest.getAttributeRequest("sAMAccountName").getValue())){
          attValue = accountRequest.getAttributeRequest("sAMAccountName").getValue()+"@presencehealth.net";   
          }
          return attValue;

          import sailpoint.object.Identity;
          import sailpoint.tools.Util;

          String midNameValue = null;

          if(null != identity && Util.isNotNullOrEmpty(identity.getAttribute("middleName"))){         
          midNameValue = identity.getAttribute("middleName");
          }

          return midNameValue;

          import sailpoint.tools.Util;
          import sailpoint.object.Identity;

          String description="";

          if(null != identity && Util.isNotNullOrEmpty(identity.getAttribute("title")) && Util.isNotNullOrEmpty(identity.getAttribute("department"))){
          description = identity.getAttribute("title")+" - "+identity.getAttribute("department");          
          }
          return description;
